-- LOS marker by kvt
--Based on: Ruler Plus - Inches - by Giulianno Bessa "illugion"
--Made for Tabletop Simulator API 03/2026

--::::::::::Initialization::::::::::
function onLoad()
    --Toggles between on and off (1 and -1)
    toggleMeasure = -1;

    
    --Properties start as null, and are filled as a player first interacts with the marker
    targetObj = nil;
    playerColor = nil;
    lineColor   = nil;

    pointA = nil;
    pointB = nil;
    
    --Reset any changed object properties
    --Sets sticky to false, to be able to get picked from under another object
    self.sticky = false;

    --Sets the snap point (doesn't matter much)
    self.setSnapPoints({
        {
            position = {0,0,0},
            rotation = {0,0,0},
            rotation_snap = false
        },
    });
    
    --Clear lines if we have any (important when the marker is copy/pasted)
    self.setVectorLines({});
end

--::::::::::Toggle on + target selection::::::::::
--The first player to hover over the object owns it. This helps prevent another player who's grabbing unrelated stuff from accidentally picking the target.
function onObjectHover(color, object)
    if object == self and playerColor == nil then
        playerColor = color;
        lineColor = color;
    end
end

--Picking up any 'LOS Marker' makes any primed markers permanently pick that one as their target.
function onObjectPickUp(color, pickedObj)
    if playerColor != nil and color == playerColor then
        --If not, turns off the toggle and selects the picked object
        if pickedObj != nil and pickedObj != self and pickedObj.getName() == "LOS Marker" and toggleMeasure == -1 then
            targetObj = pickedObj;
            pointA = self.getPosition();
            toggleMeasure = 1;
        end
    end
end



function onUpdate()
    if toggleMeasure == 1 then
        --Keep the line origin up-to-date
        if self.resting == false then
            pointA = self.getPosition();
        end

        --Keep the line target up-to-date (or remove it if the target object is gone)
        if targetObj != nil and targetObj.isDestroyed() == false then
            pointB = targetObj.getPosition();
        else
            pointB = nil;
            destroyObject(self);
        end

        --::::::::::Drawing lines::::::::::
        if pointB != nil and (targetObj.resting == false) then
            if targetObj.is_face_down == false and self.is_face_down == false then
                --Line along the floor
                self.setVectorLines({
                    {
                        points    = { self.positionToLocal(pointA) + Vector(0, 0.105, 0), --Most ruins footprint models are 0.1" in TTS
                                       self.positionToLocal(pointB + Vector(0, 0.105, 0))},
                        color     = lineColor,
                        thickness = 0.1
                    },
                })
            else
                --If face-down, LOS wall instead
                targetLocal = self.positionToLocal(pointB);
                
                self.setVectorLines({
                    {
                        points    = { self.positionToLocal(pointA) + Vector(0, 0.0, 0),
                                       {0,0,Vector.distance(pointA,pointB) / self.getScale()[1]}},
                        color     = lineColor,
                        thickness = 10,
                        rotation  = {0,targetLocal:heading('y'),90}
                    },
                })
            end
        end
        --Workaround for vector lines disappearing after you draw too many: while self is moving, we can assume our partner marker is drawing a line to us. This lets us at least double how long you can spend adjusting lines
        if pointB != nil and self.resting == false and targetObj.resting == true then
            self.setVectorLines({});
        end
    end
end

